import { _decorator, Component, director, Node, Label, Button, ProgressBar, Sprite } from 'cc';
import { NetworkManager } from './NetworkManager';
import { PlayerData } from './PlayerData';
import { AudioManager } from './AudioManager';

const { ccclass, property } = _decorator;

@ccclass('GameManager')
export class GameManager extends Component {
    static instance: GameManager = null;
    
    @property(Node)
    loadingNode: Node = null;
    
    @property(Label)
    loadingLabel: Label = null;
    
    network: NetworkManager = null;
    playerData: PlayerData = null;
    audioManager: AudioManager = null;
    
    onLoad() {
        if (GameManager.instance === null) {
            GameManager.instance = this;
            director.addPersistRootNode(this.node);
            this.init();
        } else {
            this.destroy();
        }
    }
    
    async init() {
        this.showLoading('正在初始化...');
        
        // 初始化网络
        this.network = new NetworkManager();
        await this.network.init();
        
        // 初始化玩家数据
        this.playerData = new PlayerData();
        await this.playerData.load();
        
        // 初始化音频
        this.audioManager = new AudioManager();
        
        this.hideLoading();
        
        // 检查登录状态
        if (!this.playerData.isLoggedIn()) {
            director.loadScene('LoginScene');
        } else {
            director.loadScene('MainScene');
        }
    }
    
    showLoading(text: string = '加载中...') {
        if (this.loadingNode) {
            this.loadingNode.active = true;
            this.loadingLabel.string = text;
        }
    }
    
    hideLoading() {
        if (this.loadingNode) {
            this.loadingNode.active = false;
        }
    }
    
    static getInstance(): GameManager {
        return GameManager.instance;
    }
}
